import React, { useState, useEffect, useMemo } from 'react';
import { GoogleGenAI, Type } from "@google/genai";
import { fetchDigest, createResource } from '../services/api';
import { NewsItem } from '../types';
import { 
  Zap, 
  RefreshCw, 
  ExternalLink, 
  BrainCircuit, 
  Loader2, 
  X,
  FileJson,
  CheckCircle2,
  AlertCircle,
  Save,
  ShieldAlert,
  Globe,
  Sparkles,
  Search,
  BookOpenCheck,
  Flame,
  Clock,
  LayoutGrid,
  List,
  Terminal
} from 'lucide-react';
import { parse } from 'marked';

export const IntelligenceDigest: React.FC = () => {
  const [items, setItems] = useState<NewsItem[]>([]);
  const [loading, setLoading] = useState(false);
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');

  // AI States
  const [summary, setSummary] = useState<string | null>(null);
  const [summarizing, setSummarizing] = useState(false);

  // Triage States
  const [urlInput, setUrlInput] = useState("");
  const [analyzing, setAnalyzing] = useState(false);
  const [detectedType, setDetectedType] = useState<string | null>(null);
  const [formData, setFormData] = useState<any>(null);
  const [isSaving, setIsSaving] = useState(false);
  const [showModal, setShowModal] = useState(false);

  // Initialize Gemini AI following guidelines
  const ai = useMemo(() => new GoogleGenAI({ apiKey: process.env.API_KEY as string }), []);

  const loadData = async () => {
    setLoading(true);
    try {
      const data = await fetchDigest(3);
      setItems(data);
    } catch (err) {
      console.error("Error loading digest data:", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const generateBriefSummary = async (newsItems: NewsItem[]) => {
    if (newsItems.length === 0) return;
    setSummarizing(true);
    try {
      const newsContent = newsItems.slice(0, 12).map(item => 
        `- [${item.feedTitle}] ${item.title}: ${item.description?.substring(0, 150)}...`
      ).join('\n');

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Actúa como un Analista Senior de CTI. Resume la siguiente lista de noticias en un informe ejecutivo conciso. Enfócate en amenazas emergentes, vulnerabilidades críticas y campañas globales. Usa markdown con secciones para "Amenazas Destacadas", "Vulnerabilidades Críticas" y "Acciones Recomendadas".\n\nNoticias:\n${newsContent}`,
      });

      setSummary(response.text || "No se pudo generar el resumen.");
    } catch (error) {
      console.error("Summary generation error:", error);
      setSummary("Error al generar el resumen ejecutivo. Por favor, intente de nuevo.");
    } finally {
      setSummarizing(false);
    }
  };

  const handleAnalizar = async (url: string, newsItem?: NewsItem) => {
    setAnalyzing(true);
    setShowModal(true);
    setFormData(null);
    setDetectedType(null);

    try {
      const context = newsItem 
        ? `Título: ${newsItem.title}\nDescripción: ${newsItem.description}\nFuente: ${newsItem.feedTitle}` 
        : `URL a analizar: ${url}`;

      const prompt = `Analiza esta fuente de inteligencia y mapeala a uno de estos tipos: 'incidente', 'exploit', 'zeroday', 'cve', o 'alerta'. Extrae todos los campos posibles.\nContexto:\n${context}`;

      // Use responseSchema for high reliability in extraction
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              type: { 
                type: Type.STRING, 
                description: "El tipo de recurso detectado: 'incidente', 'exploit', 'zeroday', 'cve', o 'alerta'." 
              },
              data: {
                type: Type.OBJECT,
                description: "Los datos mapeados según el esquema del recurso.",
                properties: {
                  // Common fields
                  fecha: { type: Type.STRING, description: "Fecha en formato YYYY-MM-DD" },
                  url: { type: Type.STRING },
                  descripcion: { type: Type.STRING },
                  // Incidente
                  tipo: { type: Type.STRING },
                  entidad: { type: Type.STRING },
                  pais: { type: Type.STRING },
                  sector: { type: Type.STRING },
                  actor: { type: Type.STRING },
                  // Exploit
                  nombre: { type: Type.STRING },
                  plataforma: { type: Type.STRING },
                  cve: { type: Type.STRING },
                  // CVE
                  cveId: { type: Type.STRING },
                  aplicativo: { type: Type.STRING },
                  cvss: { type: Type.NUMBER },
                  estado: { type: Type.STRING },
                  // Alerta
                  titulo: { type: Type.STRING },
                  criticidad: { type: Type.STRING, description: "Baja, Media, Alta o Critica" },
                  // ZeroDay
                  idZD: { type: Type.STRING }
                }
              }
            },
            required: ["type", "data"]
          }
        }
      });

      const result = JSON.parse(response.text || '{}');
      setDetectedType(result.type);
      setFormData(result.data);
    } catch (err) {
      console.error("AI Triage error:", err);
      setFormData({ error: "Error de análisis. La IA no pudo estructurar los datos de esta fuente." });
    } finally {
      setAnalyzing(false);
    }
  };

  const handleFieldChange = (key: string, value: any) => {
    setFormData((prev: any) => ({ ...prev, [key]: value }));
  };

  const handleSaveResource = async () => {
    if (!detectedType || !formData) return;
    setIsSaving(true);
    try {
      const res = await createResource(detectedType, formData);
      if (res.success) {
        setShowModal(false);
        setFormData(null);
        setDetectedType(null);
        setUrlInput("");
        loadData();
      } else {
        alert("Error al persistir inteligencia: " + res.message);
      }
    } catch (err) {
      console.error("Save error:", err);
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <div className="space-y-8 pb-12">
      {/* Header & Triage Input */}
      <div className="bg-gradient-to-br from-slate-900 via-indigo-950 to-indigo-900 text-white p-10 rounded-[2rem] shadow-2xl border border-indigo-500/20 relative overflow-hidden">
        <div className="absolute -top-24 -right-24 opacity-10 pointer-events-none">
            <BrainCircuit className="w-96 h-96 text-indigo-400" />
        </div>

        <div className="relative z-10 max-w-4xl">
            <div className="flex items-center gap-3 mb-4">
              <div className="bg-indigo-500/20 backdrop-blur-md text-indigo-300 text-[10px] font-black uppercase tracking-[0.2em] px-4 py-1.5 rounded-full border border-indigo-500/30 flex items-center gap-2">
                <Sparkles className="w-3 h-3" />
                SATI AI Integration v4.0
              </div>
            </div>
            <h2 className="text-4xl md:text-5xl font-black mb-4 flex items-center gap-4 tracking-tighter">
                <Zap className="w-12 h-12 text-amber-400 fill-amber-400 drop-shadow-[0_0_15px_rgba(251,191,36,0.5)]" />
                Intelligence Hub
            </h2>
            <p className="text-slate-300 mb-10 text-lg leading-relaxed font-medium max-w-2xl">
                Procesamiento de fuentes globales en tiempo real. Utiliza IA para extraer vulnerabilidades, campañas y exploits directamente a tu base de datos CTI.
            </p>

            <form 
              onSubmit={(e) => { e.preventDefault(); handleAnalizar(urlInput); }}
              className="flex flex-col md:flex-row gap-4"
            >
                <div className="relative flex-1 group">
                    <Globe className="absolute left-5 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-500 group-focus-within:text-amber-400 transition-colors" />
                    <input 
                        type="url"
                        placeholder="URL de inteligencia (BleepingComputer, DarkReading, GitHub...)"
                        value={urlInput}
                        onChange={(e) => setUrlInput(e.target.value)}
                        className="w-full pl-14 pr-6 py-5 bg-slate-800/40 border border-slate-700/50 rounded-2xl focus:ring-2 focus:ring-amber-500/50 outline-none text-slate-100 placeholder:text-slate-500 transition-all font-semibold backdrop-blur-md"
                        required
                    />
                </div>
                <button 
                    type="submit"
                    disabled={analyzing || !urlInput}
                    className="px-10 py-5 bg-amber-500 hover:bg-amber-400 text-slate-950 font-black rounded-2xl shadow-xl shadow-amber-900/20 transition-all flex items-center justify-center gap-3 active:scale-95 disabled:opacity-50"
                >
                    {analyzing ? <Loader2 className="w-6 h-6 animate-spin" /> : <Search className="w-6 h-6" />}
                    Triaje de Fuente
                </button>
            </form>
        </div>
      </div>

      {/* AI Brief Summary */}
      <div className="bg-white rounded-[2rem] border border-indigo-50 shadow-xl overflow-hidden group">
        <div className="p-8 border-b border-indigo-50 flex flex-col md:flex-row justify-between items-center gap-4 bg-indigo-50/20">
          <div className="flex items-center gap-4">
            <div className="bg-indigo-600 p-3 rounded-2xl shadow-lg shadow-indigo-100">
              <BookOpenCheck className="w-6 h-6 text-white" />
            </div>
            <div>
              <h3 className="text-xl font-bold text-slate-800">Brief Ejecutivo Diario</h3>
              <p className="text-sm text-slate-500 font-medium">Análisis sintético de la postura de amenaza actual</p>
            </div>
          </div>
          <button 
            onClick={() => generateBriefSummary(items)}
            disabled={summarizing || items.length === 0}
            className="flex items-center gap-2 px-8 py-3 bg-indigo-600 text-white rounded-2xl text-sm font-black hover:bg-indigo-700 transition-all disabled:opacity-50 shadow-xl shadow-indigo-200 active:scale-95"
          >
            {summarizing ? <Loader2 className="w-4 h-4 animate-spin" /> : <Sparkles className="w-4 h-4" />}
            {summary ? 'Actualizar Análisis' : 'Generar Informe IA'}
          </button>
        </div>

        <div className="p-8">
          {summarizing ? (
            <div className="flex flex-col items-center justify-center py-16 gap-5">
              <div className="relative">
                <div className="w-16 h-16 border-4 border-indigo-100 border-t-indigo-600 rounded-full animate-spin"></div>
                <Zap className="w-6 h-6 text-indigo-600 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2" />
              </div>
              <p className="text-slate-500 font-bold animate-pulse">Destilando inteligencia estratégica...</p>
            </div>
          ) : summary ? (
            <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
              <div 
                className="prose prose-indigo max-w-none bg-slate-50/50 p-10 rounded-3xl border border-slate-100 font-sans text-slate-800 leading-relaxed text-base"
                dangerouslySetInnerHTML={{ __html: parse(summary) as string }}
              />
            </div>
          ) : (
            <div className="text-center py-16 text-slate-400 bg-slate-50/50 rounded-3xl border border-dashed border-slate-200">
              <Terminal className="w-16 h-16 mx-auto mb-4 opacity-10" />
              <p className="font-bold text-lg">Inicia el análisis de IA para obtener una visión resumida de los feeds.</p>
            </div>
          )}
        </div>
      </div>

      {/* Main Observatory Feed */}
      <div className="space-y-6">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center px-4 gap-4">
            <div className="flex items-center gap-4">
              <div className="bg-orange-500 p-2 rounded-xl shadow-lg shadow-orange-100">
                <Flame className="w-6 h-6 text-white" />
              </div>
              <h3 className="text-2xl font-black text-slate-900 tracking-tight">Observatorio de Inteligencia</h3>
              <div className="h-6 w-px bg-slate-200 hidden md:block"></div>
              <span className="bg-slate-100 text-slate-500 px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest border border-slate-200">
                Live Feed
              </span>
            </div>

            <div className="flex items-center gap-2 bg-white p-1.5 rounded-2xl border border-slate-200 shadow-sm">
              <button 
                onClick={() => setViewMode('grid')}
                className={`p-2.5 rounded-xl transition-all ${viewMode === 'grid' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:bg-slate-50'}`}
              >
                <LayoutGrid className="w-5 h-5" />
              </button>
              <button 
                onClick={() => setViewMode('list')}
                className={`p-2.5 rounded-xl transition-all ${viewMode === 'list' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:bg-slate-50'}`}
              >
                <List className="w-5 h-5" />
              </button>
              <div className="w-px h-6 bg-slate-100 mx-1"></div>
              <button 
                onClick={loadData}
                disabled={loading}
                className="p-2.5 text-slate-500 hover:text-indigo-600 transition-colors"
                title="Sincronizar fuentes"
              >
                <RefreshCw className={`w-5 h-5 ${loading ? 'animate-spin' : ''}`} />
              </button>
            </div>
        </div>

        {loading ? (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                {[1,2,3,4,5,6].map(i => (
                  <div key={i} className="bg-white h-72 rounded-3xl animate-pulse border border-slate-100"></div>
                ))}
            </div>
        ) : items.length === 0 ? (
            <div className="text-center py-24 bg-white rounded-[3rem] border-2 border-dashed border-slate-200">
                <Globe className="w-20 h-20 text-slate-200 mx-auto mb-4" />
                <p className="text-slate-400 font-bold text-xl">No hay noticias recientes en los feeds configurados.</p>
            </div>
        ) : (
            <div className={viewMode === 'grid' ? "grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8" : "space-y-4"}>
                {items.map((item, idx) => (
                    <div 
                      key={idx} 
                      className={`
                        bg-white rounded-3xl border border-slate-200 overflow-hidden hover:shadow-2xl hover:border-indigo-300 transition-all flex flex-col group relative
                        ${viewMode === 'list' ? 'flex-row items-center gap-8 p-6' : ''}
                      `}
                    >
                        <div className={viewMode === 'grid' ? "p-8 flex-1" : "flex-1"}>
                            <div className="flex justify-between items-center mb-5">
                                <span className="px-3 py-1 bg-indigo-50 text-indigo-600 text-[10px] font-black uppercase rounded-lg tracking-widest border border-indigo-100">
                                    {item.feedTitle}
                                </span>
                                <div className="flex items-center gap-2 text-[10px] text-slate-400 font-black uppercase">
                                  <Clock className="w-3.5 h-3.5" />
                                  {new Date(item.pubDate).toLocaleDateString()}
                                </div>
                            </div>
                            <h4 className="font-bold text-slate-900 leading-tight mb-4 group-hover:text-indigo-600 transition-colors text-xl tracking-tight">
                                {item.title}
                            </h4>
                            <p className="text-sm text-slate-500 line-clamp-3 leading-relaxed font-medium">
                                {item.description?.replace(/<[^>]*>?/gm, '') || 'Sin descripción disponible.'}
                            </p>
                        </div>
                        <div className={viewMode === 'grid' ? "px-8 py-5 bg-slate-50 border-t border-slate-100 flex items-center justify-between" : "flex flex-col gap-3 min-w-[140px]"}>
                            <a 
                              href={item.link} 
                              target="_blank" 
                              rel="noreferrer" 
                              className="text-slate-400 hover:text-indigo-600 p-2.5 hover:bg-white rounded-2xl transition-all"
                              title="Ver Fuente Original"
                            >
                                <ExternalLink className="w-6 h-6" />
                            </a>
                            <button 
                                onClick={() => handleAnalizar(item.link, item)}
                                className="px-6 py-3 bg-slate-900 text-white text-[11px] font-black rounded-2xl hover:bg-indigo-600 transition-all flex items-center gap-2 shadow-xl shadow-slate-200 active:scale-95"
                            >
                                <Zap className="w-4 h-4 text-amber-400 fill-amber-400" />
                                Triaje IA
                            </button>
                        </div>
                    </div>
                ))}
            </div>
        )}
      </div>

      {/* Triage Review Modal */}
      {showModal && (
        <div className="fixed inset-0 bg-slate-950/80 z-50 flex items-center justify-center p-4 backdrop-blur-md">
            <div className="bg-white rounded-[3rem] shadow-[0_32px_64px_-12px_rgba(0,0,0,0.5)] w-full max-w-4xl max-h-[90vh] flex flex-col animate-in fade-in zoom-in slide-in-from-bottom-8 duration-500 overflow-hidden border border-slate-200">
                <div className="flex justify-between items-center p-8 border-b border-slate-100 bg-slate-50/50">
                    <div className="flex items-center gap-6">
                        <div className="bg-amber-500 p-4 rounded-3xl shadow-2xl shadow-amber-200">
                            <BrainCircuit className="w-10 h-10 text-white" />
                        </div>
                        <div>
                            <h3 className="text-2xl font-black text-slate-900 tracking-tighter">SATI Triaje Engine</h3>
                            <div className="flex items-center gap-3 mt-1.5">
                                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Pipeline de Extracción:</span>
                                <span className={`text-[10px] font-black uppercase px-3 py-1 rounded-full border ${analyzing ? 'bg-amber-50 text-amber-700 border-amber-200 animate-pulse' : 'bg-green-50 text-green-700 border-green-200'}`}>
                                    {analyzing ? 'Analizando Semántica...' : 'Estructura Validada'}
                                </span>
                            </div>
                        </div>
                    </div>
                    {!analyzing && (
                        <button onClick={() => setShowModal(false)} className="text-slate-300 hover:text-slate-900 p-3 hover:bg-slate-100 rounded-full transition-all">
                            <X className="w-8 h-8" />
                        </button>
                    )}
                </div>

                <div className="flex-1 overflow-y-auto p-10 bg-slate-50/30">
                    {analyzing ? (
                        <div className="h-full flex flex-col items-center justify-center text-center py-20">
                            <div className="relative mb-12">
                                <div className="w-36 h-36 border-[8px] border-amber-50 border-t-amber-500 rounded-full animate-spin"></div>
                                <Zap className="w-16 h-16 text-amber-500 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 fill-current drop-shadow-[0_0_20px_rgba(245,158,11,0.6)]" />
                            </div>
                            <h4 className="text-3xl font-black text-slate-900 mb-4 tracking-tighter">Mapeando Inteligencia</h4>
                            <p className="text-slate-500 max-w-sm mx-auto text-lg leading-relaxed font-medium">Categorizando hallazgos y normalizando campos según el esquema de OSINT Brief.</p>
                        </div>
                    ) : formData ? (
                        <div className="space-y-10">
                            <div className="flex items-center justify-between bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
                                <div className="flex items-center gap-4">
                                    <div className="p-3 bg-green-100 rounded-2xl">
                                        <CheckCircle2 className="w-7 h-7 text-green-600" />
                                    </div>
                                    <h4 className="font-black text-slate-800 uppercase tracking-tight text-sm">
                                      Hallazgo detectado: <span className="text-indigo-600 font-black px-3 py-1 bg-indigo-50 rounded-lg ml-2">{detectedType?.toUpperCase()}</span>
                                    </h4>
                                </div>
                                <div className="text-[10px] font-black text-slate-300 uppercase tracking-widest">
                                    Motor Gemini 3 Flash
                                </div>
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 bg-white p-12 rounded-[2.5rem] border border-slate-200 shadow-2xl relative overflow-hidden">
                                <div className="absolute top-0 left-0 w-4 h-full bg-indigo-600"></div>
                                {Object.keys(formData).map((key) => {
                                    if (key === 'error') return null;
                                    return (
                                        <div key={key} className={key === 'descripcion' ? 'md:col-span-2' : ''}>
                                            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-3 ml-2">
                                                {key.replace(/([A-Z])/g, ' $1').trim()}
                                            </label>
                                            {key === 'descripcion' ? (
                                                <textarea 
                                                    value={formData[key]}
                                                    onChange={(e) => handleFieldChange(key, e.target.value)}
                                                    className="w-full p-6 bg-slate-50 border-2 border-slate-100 rounded-2xl text-base font-semibold text-slate-700 focus:ring-4 focus:ring-amber-500/10 focus:border-amber-500 focus:bg-white outline-none min-h-[180px] transition-all resize-none shadow-inner"
                                                />
                                            ) : (
                                                <input 
                                                    type={key === 'fecha' ? 'date' : (typeof formData[key] === 'number' ? 'number' : 'text')}
                                                    value={formData[key]}
                                                    onChange={(e) => handleFieldChange(key, e.target.value)}
                                                    className="w-full p-6 bg-slate-50 border-2 border-slate-100 rounded-2xl text-base font-bold text-slate-900 focus:ring-4 focus:ring-amber-500/10 focus:border-amber-500 focus:bg-white outline-none transition-all shadow-inner"
                                                />
                                            )}
                                        </div>
                                    );
                                })}
                                {formData.error && (
                                  <div className="col-span-full p-12 text-center text-red-500 bg-red-50 rounded-3xl border-2 border-red-100">
                                    <AlertCircle className="w-16 h-16 mx-auto mb-5" />
                                    <p className="font-black text-xl">{formData.error}</p>
                                  </div>
                                )}
                            </div>

                            <div className="bg-slate-900 p-10 rounded-[2.5rem] flex items-start gap-6 shadow-2xl">
                                <ShieldAlert className="w-12 h-12 text-amber-500 mt-1 flex-shrink-0" />
                                <div>
                                    <p className="font-black text-white text-xl mb-2">Revisión Final de Integridad</p>
                                    <p className="text-slate-400 text-base leading-relaxed font-medium">
                                      Verifica los campos extraídos antes de persistirlos. Una vez registrado, este hallazgo alimentará el Dashboard, las estadísticas de riesgo y los reportes ejecutivos.
                                    </p>
                                </div>
                            </div>
                        </div>
                    ) : null}
                </div>

                <div className="p-10 border-t border-slate-100 bg-white flex flex-col md:flex-row justify-between items-center gap-8">
                    <div className="flex items-center gap-4 text-xs font-black text-slate-300 uppercase tracking-widest">
                        <FileJson className="w-6 h-6 text-indigo-400" />
                        SATI_DATA_STREAM: {Math.random().toString(36).substring(7).toUpperCase()}
                    </div>
                    <div className="flex gap-4 w-full md:w-auto">
                        <button 
                            onClick={() => setShowModal(false)}
                            className="flex-1 md:flex-none px-12 py-5 text-slate-500 font-black hover:bg-slate-50 rounded-2xl transition-all border-2 border-slate-100 hover:border-slate-200 active:scale-95"
                        >
                            Cerrar
                        </button>
                        <button 
                            onClick={handleSaveResource}
                            disabled={isSaving || !formData || formData.error}
                            className="flex-1 md:flex-none px-16 py-5 bg-indigo-600 hover:bg-indigo-700 text-white font-black rounded-2xl shadow-2xl shadow-indigo-300 transition-all flex items-center justify-center gap-3 active:scale-95 disabled:opacity-50"
                        >
                            {isSaving ? <Loader2 className="w-6 h-6 animate-spin" /> : <Save className="w-6 h-6" />}
                            Persistir Inteligencia
                        </button>
                    </div>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { GoogleGenAI, Type } from "@google/genai";
import { fetchDigest, createResource } from '../services/api';
import { NewsItem } from '../types';
import { 
  Zap, 
  RefreshCw, 
  ExternalLink, 
  BrainCircuit, 
  Loader2, 
  X,
  FileJson,
  CheckCircle2,
  AlertCircle,
  Save,
  ShieldAlert,
  Globe,
  Sparkles,
  Search,
  BookOpenCheck,
  Flame,
  Clock,
  LayoutGrid,
  List,
  Terminal,
  Activity,
  Target
} from 'lucide-react';
import { parse } from 'marked';

export const IntelligenceDigest: React.FC = () => {
  const [items, setItems] = useState<NewsItem[]>([]);
  const [loading, setLoading] = useState(false);
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');

  // AI States
  const [summary, setSummary] = useState<string | null>(localStorage.getItem('cti_last_summary'));
  const [summarizing, setSummarizing] = useState(false);

  // Triage States
  const [urlInput, setUrlInput] = useState("");
  const [analyzing, setAnalyzing] = useState(false);
  const [detectedType, setDetectedType] = useState<string | null>(null);
  const [formData, setFormData] = useState<any>(null);
  const [isSaving, setIsSaving] = useState(false);
  const [showModal, setShowModal] = useState(false);

  const ai = useMemo(() => new GoogleGenAI({ apiKey: process.env.API_KEY as string }), []);

  const loadData = async () => {
    setLoading(true);
    try {
      const data = await fetchDigest(3);
      setItems(data);
    } catch (err) {
      console.error("Error loading digest data:", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const generateBriefSummary = async (newsItems: NewsItem[]) => {
    if (newsItems.length === 0) return;
    setSummarizing(true);
    try {
      const newsContent = newsItems.slice(0, 15).map(item => 
        `- [${item.feedTitle}] ${item.title}: ${item.description?.substring(0, 200)}...`
      ).join('\n');

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
