  const [isSaving, setIsSaving] = useState(false);
  const [showModal, setShowModal] = useState(false);

  const ai = useMemo(() => new GoogleGenAI({ apiKey: process.env.API_KEY as string }), []);

  const loadData = async () => {
    setLoading(true);
    try {
      const data = await fetchDigest(3);
      setItems(data);
    } catch (err) {
      console.error("Error loading digest data:", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const generateBriefSummary = async (newsItems: NewsItem[]) => {
    if (newsItems.length === 0) return;
    setSummarizing(true);
    try {
      const newsContent = newsItems.slice(0, 15).map(item => 
        `- [${item.feedTitle}] ${item.title}: ${item.description?.substring(0, 200)}...`
      ).join('\n');

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Actúa como un Analista Senior de CTI. Resume las siguientes noticias en un informe estratégico ejecutivo conciso. Usa markdown y destaca amenazas críticas.\n\nNoticias:\n${newsContent}`,
      });

      const text = response.text || "No se pudo generar el resumen.";
      setSummary(text);
      localStorage.setItem('cti_last_summary', text);
      // Disparamos un evento para que el dashboard sepa que hay nuevo resumen si está abierto
      window.dispatchEvent(new Event('storage'));
    } catch (error) {
      console.error("Summary error:", error);
      setSummary("Error al generar el informe.");
    } finally {
      setSummarizing(false);
    }
  };

  const handleAnalizar = async (url: string, newsItem?: NewsItem) => {
    setAnalyzing(true);
    setShowModal(true);
    setFormData(null);
    setDetectedType(null);
    try {
      const context = newsItem ? `Noticia: ${newsItem.title}. Contenido: ${newsItem.description}` : `Fuente: ${url}`;
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Analiza esta fuente CTI y extrae datos estructurados. URL: ${url}. Contexto: ${context}`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              type: { type: Type.STRING, description: "Tipo detectado: incidente, exploit, zeroday, cve, alerta" },
              data: {
                type: Type.OBJECT,
                properties: {
                  fecha: { type: Type.STRING },
                  url: { type: Type.STRING },
                  descripcion: { type: Type.STRING },
                  tipo: { type: Type.STRING },
                  entidad: { type: Type.STRING },
                  nombre: { type: Type.STRING },
                  criticidad: { type: Type.STRING },
                  cvss: { type: Type.NUMBER },
                  cveId: { type: Type.STRING },
                  aplicativo: { type: Type.STRING }
                }
              }
            },
            required: ["type", "data"]
          }
        }
      });
      const result = JSON.parse(response.text || '{}');
      setDetectedType(result.type);
      setFormData(result.data);
    } catch (err) {
      setFormData({ error: "Error de análisis IA" });
    } finally {
      setAnalyzing(false);
    }
  };

  const handleSaveResource = async () => {
    if (!detectedType || !formData) return;
    setIsSaving(true);
    try {
      const endpointMap: Record<string, string> = { 'cve': 'cves', 'alerta': 'alertas', 'incidente': 'incidentes', 'exploit': 'exploits', 'zeroday': 'zerodays' };
      const endpoint = endpointMap[detectedType] || detectedType;
      const res = await createResource(endpoint, formData);
      if (res.success) {
        setShowModal(false);
        setUrlInput("");
        loadData();
      } else {
        alert("Error: " + res.message);
      }
    } catch (err) {
      console.error(err);
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <div className="space-y-10 pb-20">
      <div className="bg-slate-950 rounded-[2.5rem] border border-slate-800 p-12 shadow-2xl relative overflow-hidden">
        <div className="absolute top-0 right-0 w-1/3 h-full bg-indigo-500/10 blur-[100px]"></div>
        <div className="relative z-10 flex flex-col lg:flex-row gap-12 items-center">
          <div className="flex-1 space-y-6">
            <div className="flex items-center gap-3">
              <span className="flex h-3 w-3"><span className="animate-ping absolute h-3 w-3 rounded-full bg-amber-400 opacity-75"></span><span className="relative h-3 w-3 rounded-full bg-amber-500"></span></span>
              <span className="text-[10px] font-black uppercase tracking-[0.3em] text-amber-500">SATI Engine v4.2</span>
            </div>
            <h1 className="text-5xl font-black text-white tracking-tighter">SATI <span className="text-indigo-400">Intelligence Hub</span></h1>
            <p className="text-slate-400 text-lg max-w-xl font-medium">Extrae inteligencia estratégica de fuentes globales automáticamente.</p>
            <form onSubmit={(e) => { e.preventDefault(); handleAnalizar(urlInput); }} className="flex gap-4">
              <input 
                type="url" placeholder="Paste CTI Source URL..." value={urlInput} onChange={(e) => setUrlInput(e.target.value)}
                className="flex-1 bg-slate-900 border border-slate-800 rounded-2xl py-4 px-6 text-white font-bold focus:ring-2 focus:ring-indigo-500/50 outline-none"
              />
              <button disabled={analyzing || !urlInput} className="bg-indigo-600 hover:bg-indigo-500 text-white px-10 rounded-2xl font-black flex items-center gap-3 transition-all active:scale-95 disabled:opacity-50">
                {analyzing ? <Loader2 className="animate-spin w-5 h-5" /> : <Zap className="w-5 h-5" />}
                Triaje IA
              </button>
            </form>
          </div>
          <div className="lg:w-1/3 bg-slate-900/50 p-8 rounded-[2rem] border border-slate-800 space-y-4">
             <div className="flex items-center gap-2 text-white font-black text-xs uppercase"><Activity className="w-4 h-4 text-indigo-400" /> Stats Operativas</div>
             <div className="grid grid-cols-2 gap-4">
                <div className="bg-slate-950 p-4 rounded-xl border border-slate-800 text-center"><div className="text-2xl font-black text-white">{items.length}</div><div className="text-[9px] text-slate-500 font-bold uppercase">Feeds Hoy</div></div>
                <div className="bg-slate-950 p-4 rounded-xl border border-slate-800 text-center"><div className="text-2xl font-black text-amber-500">{items.filter(i => i.title.toLowerCase().includes('zero')).length}</div><div className="text-[9px] text-slate-500 font-bold uppercase">Amenazas ZD</div></div>
             </div>
             <button onClick={() => generateBriefSummary(items)} className="w-full py-4 bg-slate-800 hover:bg-slate-700 text-white rounded-xl text-xs font-black uppercase flex items-center justify-center gap-2">
                {summarizing ? <Loader2 className="animate-spin w-4 h-4" /> : <Sparkles className="w-4 h-4 text-amber-400" />} Generar Resumen Ejecutivo
             </button>
          </div>
        </div>
      </div>

      {summary && (
        <div className="bg-white rounded-[2.5rem] border border-indigo-100 shadow-xl overflow-hidden animate-in fade-in slide-in-from-bottom-4">
          <div className="p-8 border-b border-indigo-50 flex items-center justify-between bg-indigo-50/20">
            <div className="flex items-center gap-4">
              <div className="bg-indigo-600 p-3 rounded-2xl shadow-lg"><BookOpenCheck className="w-6 h-6 text-white" /></div>
              <div><h3 className="text-xl font-black text-slate-900">Briefing Estratégico</h3><p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">IA Insight Output</p></div>
            </div>
            <button onClick={() => setSummary(null)} className="p-2 text-slate-300 hover:text-red-500 transition-colors"><X className="w-6 h-6" /></button>
          </div>
          <div className="p-10"><div className="prose prose-indigo max-w-none text-slate-700 font-medium" dangerouslySetInnerHTML={{ __html: parse(summary) as string }} /></div>
        </div>
      )}

      <div className="space-y-6">
        <div className="flex items-center justify-between px-6">
           <h2 className="text-2xl font-black text-slate-900 flex items-center gap-3"><Flame className="w-6 h-6 text-orange-500" /> Observatorio Global</h2>
           <div className="flex bg-white p-1 rounded-xl border border-slate-200 shadow-sm">
              <button onClick={() => setViewMode('grid')} className={`p-2 rounded-lg ${viewMode === 'grid' ? 'bg-slate-900 text-white' : 'text-slate-400'}`}><LayoutGrid className="w-5 h-5" /></button>
              <button onClick={() => setViewMode('list')} className={`p-2 rounded-lg ${viewMode === 'list' ? 'bg-slate-900 text-white' : 'text-slate-400'}`}><List className="w-5 h-5" /></button>
           </div>
        </div>
        <div className={viewMode === 'grid' ? "grid grid-cols-1 md:grid-cols-3 gap-8" : "space-y-4 px-6"}>
          {loading ? [1,2,3].map(i => <div key={i} className="h-64 bg-slate-100 rounded-[2rem] animate-pulse"></div>) : 
           items.map((item, idx) => (
            <div key={idx} className="bg-white rounded-[2rem] border border-slate-100 p-8 hover:shadow-2xl transition-all group flex flex-col justify-between">
              <div>
                <div className="flex justify-between items-center mb-6"><span className="bg-indigo-50 text-indigo-600 text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-widest">{item.feedTitle}</span><Clock className="w-4 h-4 text-slate-300" /></div>
                <h3 className="text-xl font-black text-slate-900 mb-4 group-hover:text-indigo-600">{item.title}</h3>
                <p className="text-slate-500 text-sm line-clamp-3 mb-6 font-medium">{item.description?.replace(/<[^>]*>?/gm, '')}</p>
              </div>
              <div className="flex items-center justify-between pt-6 border-t border-slate-50">
                 <a href={item.link} target="_blank" rel="noreferrer" className="text-slate-300 hover:text-indigo-600"><ExternalLink className="w-5 h-5" /></a>
                 <button onClick={() => handleAnalizar(item.link, item)} className="flex items-center gap-2 bg-slate-900 text-white text-[10px] font-black uppercase px-6 py-3 rounded-xl hover:bg-indigo-600 transition-all"><Zap className="w-3.5 h-3.5 text-amber-400 fill-current" /> Analizar IA</button>
              </div>
            </div>
          ))}
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 bg-slate-950/90 z-50 flex items-center justify-center p-4 backdrop-blur-md">
           <div className="bg-white rounded-[3rem] w-full max-w-4xl max-h-[90vh] overflow-hidden flex flex-col shadow-2xl animate-in zoom-in duration-300">
              <div className="p-10 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
                <div className="flex items-center gap-6"><div className="bg-amber-500 p-4 rounded-3xl"><BrainCircuit className="w-8 h-8 text-white" /></div><div><h2 className="text-2xl font-black text-slate-900 tracking-tighter">SATI Data Extractor</h2><p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Estructuración de Inteligencia IA</p></div></div>
                <button onClick={() => setShowModal(false)}><X className="w-8 h-8 text-slate-300 hover:text-slate-900" /></button>
              </div>
              <div className="flex-1 overflow-y-auto p-12">
                {analyzing ? <div className="py-20 flex flex-col items-center justify-center gap-6"><div className="w-20 h-20 border-4 border-indigo-100 border-t-indigo-600 rounded-full animate-spin"></div><p className="text-slate-500 font-black text-xl animate-pulse">Normalizando vectores...</p></div> : 
                 formData && (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                    <div className="col-span-full bg-indigo-50 p-6 rounded-2xl flex items-center justify-between"><span className="text-xs font-black uppercase text-indigo-400">Detección: <span className="text-indigo-600 font-black">{detectedType?.toUpperCase()}</span></span><FileJson className="w-6 h-6 text-indigo-300" /></div>
                    {Object.entries(formData).map(([key, val]) => (
                      <div key={key} className={key === 'descripcion' ? 'col-span-full' : ''}><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 ml-2">{key}</label><input type="text" value={val as string} onChange={(e) => setFormData({...formData, [key]: e.target.value})} className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-5 font-bold text-slate-800 focus:bg-white focus:border-indigo-500 transition-all outline-none" /></div>
                    ))}
                  </div>
                )}
              </div>
              <div className="p-10 border-t border-slate-100 bg-slate-50/50 flex justify-end gap-4">
                 <button onClick={() => setShowModal(false)} className="px-10 py-5 text-slate-500 font-black hover:bg-slate-100 rounded-2xl">Cancelar</button>
                 <button onClick={handleSaveResource} disabled={isSaving || !formData} className="px-12 py-5 bg-indigo-600 hover:bg-indigo-700 text-white font-black rounded-2xl shadow-xl shadow-indigo-200 flex items-center gap-3">
                   {isSaving ? <Loader2 className="animate-spin w-5 h-5" /> : <Save className="w-5 h-5" />} Persistir en Base CTI
                 </button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

import React, { useEffect, useState, useMemo } from 'react';
import { fetchResource } from '../services/api';
import { StatCard } from './StatCard';
import { AlertTriangle, Bug, ShieldAlert, FileText, Activity, Eye, Loader2, Settings, Plus, Filter, X, Save, RotateCcw } from 'lucide-react';
import { ResponsiveContainer, BarChart, Bar, PieChart, Pie, Cell, XAxis, YAxis, CartesianGrid, Tooltip, Legend, AreaChart, Area } from 'recharts';
import { WidgetConfig, WidgetType } from '../types';
import { WidgetConfigModal } from './Dashboard/WidgetConfigModal';
import { EpssWidget } from './Dashboard/EpssWidget';
import { TimelineWidget } from './Dashboard/TimelineWidget';
import { RiskStatsWidget } from './Dashboard/RiskStatsWidget';

// --- CONSTANTS ---
const COLORS = ['#6366f1', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#64748b', '#0ea5e9'];

// Layout original restaurado
const DEFAULT_LAYOUT: WidgetConfig[] = [
  { id: 'timeline-1', title: 'Línea de Tiempo de Amenazas', type: 'special', size: 'col-span-full', specialComponent: 'timeline' },
  { id: 'risk-kpis-1', title: 'Estado de Gestión de Riesgos', type: 'special', size: 'col-span-2', specialComponent: 'risk-kpis' },
  { id: 'epss-cve-1', title: 'Priorización de CVEs (EPSS)', type: 'special', size: 'col-span-2', specialComponent: 'epss-cve' },
  { id: 'chart-inc-sector', title: 'Incidentes por Sector', type: 'chart', size: 'col-span-1', dataSource: 'incidentes', chartType: 'pie', groupByField: 'sector' },
  { id: 'chart-cve-estado', title: 'CVEs por Estado', type: 'chart', size: 'col-span-1', dataSource: 'cves', chartType: 'doughnut', groupByField: 'estado' },
];

interface DashboardProps {
  onNavigate: (tab: any) => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ onNavigate }) => {
  const [rawData, setRawData] = useState<Record<string, any[]>>({});
  const [layout, setLayout] = useState<WidgetConfig[]>([]);
  const [loading, setLoading] = useState(true);
  const [isEditMode, setIsEditMode] = useState(false);
  const [dateStart, setDateStart] = useState('');
  const [dateEnd, setDateEnd] = useState('');
  const [modalOpen, setModalOpen] = useState(false);

  useEffect(() => {
    const initDashboard = async () => {
      setLoading(true);
      const endpoints = ['incidentes', 'exploits', 'cves', 'alertas', 'zerodays', 'riesgos'];
      const rawResults: Record<string, any[]> = {};

      await Promise.all(endpoints.map(async (ep) => {
        try {
            rawResults[ep] = await fetchResource(ep);
        } catch (e) {
            rawResults[ep] = [];
        }
      }));
      setRawData(rawResults);

      const savedLayout = localStorage.getItem('dashboard_layout_v2');
      if (savedLayout) {
        try {
            const parsed = JSON.parse(savedLayout);
            setLayout(parsed.length > 0 ? parsed : DEFAULT_LAYOUT);
        } catch {
            setLayout(DEFAULT_LAYOUT);
        }
      } else {
        setLayout(DEFAULT_LAYOUT);
      }
      setLoading(false);
    };
    initDashboard();
  }, []);

  const filteredData = useMemo(() => {
    if (!dateStart && !dateEnd) return rawData;
    const start = dateStart ? new Date(dateStart) : new Date(0);
    const end = dateEnd ? new Date(dateEnd) : new Date();
    end.setHours(23, 59, 59, 999);
    const filtered: Record<string, any[]> = {};
    Object.keys(rawData).forEach(key => {
        filtered[key] = rawData[key].filter(item => {
            const dateStr = item.fecha || item.date || item.createdAt;
            if (!dateStr) return true;
            const d = new Date(dateStr);
            if (typeof dateStr === 'number') return dateStr >= start.getTime() && dateStr <= end.getTime();
            return d >= start && d <= end;
        });
    });
    return filtered;
  }, [rawData, dateStart, dateEnd]);

  const persistLayout = (newLayout: WidgetConfig[]) => {
    setLayout(newLayout);
    localStorage.setItem('dashboard_layout_v2', JSON.stringify(newLayout));
  };

  const handleUpdateWidget = (config: WidgetConfig) => {
    const newLayout = layout.map(w => w.id === config.id ? config : w);
    persistLayout(newLayout);
  };

  const handleDeleteWidget = (id: string) => {
    if (window.confirm('¿Eliminar widget?')) {
        setLayout(prev => {
            const filtered = prev.filter(w => w.id !== id);
            localStorage.setItem('dashboard_layout_v2', JSON.stringify(filtered));
            return filtered;
        });
    }
  };

  const processChartData = (widget: WidgetConfig) => {
    const source = filteredData[widget.dataSource || 'incidentes'] || [];
    const field = widget.groupByField || 'tipo';
    const counts: Record<string, number> = {};
    source.forEach(item => {
        let val = item[field] || 'N/A';
        if (Array.isArray(val)) {
             if (val.length === 0) counts['N/A'] = (counts['N/A'] || 0) + 1;
             else val.forEach(v => counts[v] = (counts[v] || 0) + 1);
             return;
        }
        if (typeof val === 'string') val = val.charAt(0).toUpperCase() + val.slice(1).replace(/-/g, ' ');
        counts[val] = (counts[val] || 0) + 1;
    });
    return Object.keys(counts).map(key => ({ name: key, value: counts[key] }))
                 .sort((a, b) => b.value - a.value).slice(0, 10);
  };

  const renderWidgetContent = (widget: WidgetConfig) => {
    if (widget.type === 'chart') {
        const data = processChartData(widget);
        if (data.length === 0) return <div className="flex items-center justify-center h-full text-gray-400 text-sm">Sin datos</div>;
        return (
            <ResponsiveContainer width="100%" height="100%">
                {widget.chartType === 'pie' || widget.chartType === 'doughnut' ? (
                    <PieChart>
                        <Pie data={data} dataKey="value" nameKey="name" cx="50%" cy="50%" outerRadius={80} innerRadius={widget.chartType === 'doughnut' ? 50 : 0} paddingAngle={2}>
                            {data.map((_, index) => <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />)}
                        </Pie>
                        <Tooltip />
                        <Legend verticalAlign="bottom" height={36} iconType="circle" wrapperStyle={{fontSize: '10px'}} />
                    </PieChart>
                ) : (
                    <BarChart data={data}>
                        <CartesianGrid strokeDasharray="3 3" vertical={false} />
                        <XAxis dataKey="name" hide={data.length > 5} tick={{fontSize: 10}} />
                        <YAxis tick={{fontSize: 10}} width={25} />
                        <Tooltip />
                        <Bar dataKey="value" fill="#6366f1" radius={[4, 4, 0, 0]}>
                            {data.map((_, index) => <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />)}
                        </Bar>
                    </BarChart>
                )}
            </ResponsiveContainer>
        );
    }

    if (widget.specialComponent === 'epss-cve') return <EpssWidget data={filteredData['cves'] || []} mode="cve" />;
    if (widget.specialComponent === 'epss-exploit') return <EpssWidget data={filteredData['exploits'] || []} referenceData={filteredData['cves']} mode="exploit" />;
    if (widget.specialComponent === 'timeline') return <TimelineWidget data={filteredData} startDate={dateStart} endDate={dateEnd} />;
    if (widget.specialComponent === 'risk-kpis') return <RiskStatsWidget data={filteredData['riesgos'] || []} />;
    if (widget.specialComponent === 'alerts-list') {
        const alerts = (filteredData['alertas'] || []).slice(0, 5);
        return (
            <div className="space-y-2 overflow-y-auto h-full pr-1 text-xs">
                {alerts.map((alert: any, i: number) => (
                    <div key={i} className={`p-2 rounded border-l-4 ${alert.criticidad === 'Critica' ? 'border-red-500 bg-red-50' : 'border-blue-500 bg-blue-50'}`}>
                        <div className="font-bold text-slate-800">{alert.titulo}</div>
                        <div className="flex justify-between mt-1 text-[10px] text-slate-500 uppercase font-bold">
                            <span>{new Date(alert.fecha).toLocaleDateString()}</span>
                            <span>{alert.criticidad}</span>
                        </div>
                    </div>
                ))}
            </div>
        );
    }
    return <div className="text-gray-400 text-xs">Componente no soportado</div>;
  };

  if (loading) return <div className="flex h-96 items-center justify-center flex-col gap-3"><Loader2 className="animate-spin w-10 h-10 text-indigo-600" /></div>;

  return (
    <div className="space-y-6 pb-20">
      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-4">
        <StatCard label="Incidentes" value={filteredData['incidentes']?.length || 0} colorClass="text-red-600" icon={<AlertTriangle className="w-4 h-4" />} onClick={() => onNavigate('incidentes')} />
        <StatCard label="Exploits" value={filteredData['exploits']?.length || 0} colorClass="text-orange-600" icon={<Activity className="w-4 h-4" />} onClick={() => onNavigate('exploits')} />
        <StatCard label="ZeroDays" value={filteredData['zerodays']?.length || 0} colorClass="text-purple-600" icon={<Bug className="w-4 h-4" />} onClick={() => onNavigate('zerodays')} />
        <StatCard label="CVEs" value={filteredData['cves']?.length || 0} colorClass="text-indigo-600" icon={<ShieldAlert className="w-4 h-4" />} onClick={() => onNavigate('cves')} />
        <StatCard label="Alertas" value={filteredData['alertas']?.length || 0} colorClass="text-blue-600" icon={<FileText className="w-4 h-4" />} onClick={() => onNavigate('alertas')} />
        <StatCard label="Observatorio" value={filteredData['digest']?.length || 'RSS'} colorClass="text-slate-600" icon={<Eye className="w-4 h-4" />} onClick={() => onNavigate('observatorio')} />
      </div>

      <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex justify-between items-center sticky top-20 z-20">
        <div className="flex items-center gap-2 bg-gray-50 px-3 py-1.5 rounded-lg border border-gray-100 text-xs">
            <Filter className="w-3.5 h-3.5 text-gray-400" />
            <input type="date" value={dateStart} onChange={e => setDateStart(e.target.value)} className="bg-transparent outline-none" />
            <span>a</span>
            <input type="date" value={dateEnd} onChange={e => setDateEnd(e.target.value)} className="bg-transparent outline-none" />
        </div>
        <div className="flex gap-2">
            {isEditMode ? (
                <button onClick={() => setIsEditMode(false)} className="px-4 py-1.5 bg-indigo-600 text-white rounded-lg text-xs font-bold shadow-lg shadow-indigo-100">Guardar Cambios</button>
            ) : (
                <button onClick={() => setIsEditMode(true)} className="px-4 py-1.5 bg-white border border-gray-200 text-gray-600 rounded-lg text-xs font-bold hover:bg-gray-50">Personalizar</button>
            )}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {layout.map((widget) => {
