import { NewsItem, RiskTicket, RssFeedConfig } from '../types';
import { GoogleGenAI, Type } from "@google/genai";

const API_BASE_URL = '/api';

// Inicialización de la IA siguiendo las guías de @google/genai
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });

let authToken: string | null = localStorage.getItem('authToken');

export const setAuthToken = (token: string | null) => {
  authToken = token;
  if (token) {
    localStorage.setItem('authToken', token);
  } else {
    localStorage.removeItem('authToken');
  }
};

const getAuthHeaders = (): HeadersInit => {
  const headers: HeadersInit = { 'Content-Type': 'application/json' };
  if (authToken) {
    headers['Authorization'] = `Bearer ${authToken}`;
  }
  return headers;
};

export interface ApiResponse {
  success: boolean;
  message?: string;
  data?: any;
}

const handleResponse = async (response: Response): Promise<ApiResponse> => {
  try {
    const contentType = response.headers.get('content-type');
    const isJson = contentType && contentType.includes('application/json');

    if (response.status === 401 || response.status === 403) {
      setAuthToken(null);
      console.warn('Authentication failed or token expired.');
    }

    if (isJson) {
      const data = await response.json();
      if (response.ok) {
        return { success: true, data: data.data || data, message: data.message };
      } else {
        return { success: false, message: data.message || `Error ${response.status}` };
      }
    } else {
      if (response.ok) return { success: true, data: null };
      const text = await response.text();
      return { success: false, message: `Error ${response.status}: ${text.substring(0, 100)}` };
    }
  } catch (error: any) {
    return { success: false, message: error.message || 'Error al procesar respuesta' };
  }
};

export const fetchResource = async <T>(endpoint: string): Promise<T[]> => {
  try {
    const response = await fetch(`${API_BASE_URL}/${endpoint}`, { headers: getAuthHeaders() });
    const result = await handleResponse(response);
    return result.success ? (result.data as T[]) : [];
  } catch (error) {
    console.error(`Fetch error for ${endpoint}:`, error);
    return [];
  }
};

export const createResource = async <T>(endpoint: string, data: T): Promise<ApiResponse> => {
  try {
    const response = await fetch(`${API_BASE_URL}/${endpoint}`, {
      method: 'POST',
      headers: getAuthHeaders(),
      body: JSON.stringify(data)
    });
    return handleResponse(response);
  } catch (error: any) {
    return { success: false, message: error.message || 'Error de conexión' };
  }
};

export const updateResource = async <T>(endpoint: string, id: string, data: T): Promise<ApiResponse> => {
  try {
    const response = await fetch(`${API_BASE_URL}/${endpoint}/${id}`, {
      method: 'PUT',
      headers: getAuthHeaders(),
      body: JSON.stringify(data)
    });
    return handleResponse(response);
  } catch (error: any) {
    return { success: false, message: error.message || 'Error de conexión' };
  }
};

export const deleteResource = async (endpoint: string, id: string): Promise<ApiResponse> => {
  try {
    const response = await fetch(`${API_BASE_URL}/${endpoint}/${id}`, {
      method: 'DELETE',
      headers: { ...getAuthHeaders(), 'Accept': 'application/json' }
    });
    if (response.status === 204) return { success: true };
    return handleResponse(response);
  } catch (error: any) {
    return { success: false, message: error.message || 'Error de conexión' };
  }
};

export const fetchRssFeeds = async (): Promise<RssFeedConfig[]> => {
  return fetchResource<RssFeedConfig>('rss-feeds');
};

export const saveRssFeed = async (feed: RssFeedConfig): Promise<ApiResponse> => {
  return createResource('rss-feeds', feed);
};

export const deleteRssFeed = async (id: string): Promise<ApiResponse> => {
  return deleteResource('rss-feeds', id);
};

export const fetchDigest = async (days: number): Promise<NewsItem[]> => {
  return fetchResource<NewsItem>(`digest?days=${days}`);
};

// --- LOGICA DE INTELIGENCIA ARTIFICIAL (CLIENT-SIDE) ---

/**
 * Genera un briefing ejecutivo a partir de una lista de noticias.
 */
export const getAIBriefing = async (newsItems: NewsItem[]): Promise<string> => {
  const newsContent = newsItems.slice(0, 15).map(item => 
    `- [${item.feedTitle}] ${item.title}: ${item.description?.substring(0, 200)}...`
  ).join('\n');

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Actúa como un Analista Senior de CTI. Resume las siguientes noticias en un informe estratégico ejecutivo conciso. Usa markdown y destaca amenazas críticas.\n\nNoticias:\n${newsContent}`,
  });

  return response.text || "No se pudo generar el resumen.";
};

/**
 * Realiza el triaje estructurado de una noticia o URL.
 */
export const performAITriage = async (url: string, newsItem?: NewsItem): Promise<{ type: string; data: any }> => {
  const context = newsItem ? `Noticia: ${newsItem.title}. Contenido: ${newsItem.description}` : `Fuente: ${url}`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Analiza esta fuente CTI y extrae datos estructurados. URL: ${url}. Contexto: ${context}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          type: { type: Type.STRING, description: "Tipo detectado: incidente, exploit, zeroday, cve, alerta" },
          data: {
            type: Type.OBJECT,
            properties: {
              fecha: { type: Type.STRING },
              url: { type: Type.STRING },
              descripcion: { type: Type.STRING },
              tipo: { type: Type.STRING },
              entidad: { type: Type.STRING },
              nombre: { type: Type.STRING },
              criticidad: { type: Type.STRING },
              cvss: { type: Type.NUMBER },
              cveId: { type: Type.STRING },
              aplicativo: { type: Type.STRING }
            }
          }
        },
        required: ["type", "data"]
      }
    }
  });

  return JSON.parse(response.text || '{}');
};

export const fetchTickets = async (): Promise<RiskTicket[]> => {
  return fetchResource<RiskTicket>('riesgos');
};

export const saveTicket = async (ticket: RiskTicket): Promise<void> => {
  if (ticket.id) {
    await updateResource('riesgos', String(ticket.id), ticket);
  } else {
    await createResource('riesgos', ticket);
  }
};

export const deleteTicket = async (id: string | number): Promise<void> => {
  await deleteResource('riesgos', String(id));
};

export const addTicketComment = async (ticketId: string | number, text: string): Promise<void> => {
  const tickets = await fetchTickets();
  const ticket = tickets.find(t => t.id === ticketId);
  if (ticket) {
    const updatedTicket = {
      ...ticket,
      lastUpdated: Date.now(),
      activity: [...ticket.activity, { type: 'comment' as const, timestamp: Date.now(), text }]
    };
    await updateResource('riesgos', String(ticketId), updatedTicket);
  }
};

export const askAI = async (query: string): Promise<{ response: string }> => {
  try {
    const res = await fetch(`${API_BASE_URL}/ai/analyze`, {
      method: 'POST',
      headers: getAuthHeaders(),
      body: JSON.stringify({ query })
    });
    const result = await handleResponse(res);
    if (result.success) return result.data as { response: string };
    throw new Error(result.message);
  } catch (error: any) {
    throw new Error(error.message || 'Error al conectar con el Analista IA');
  }
};

