              sector: { type: Type.STRING, description: "Sector industrial afectado" },
              datosComprometidos: { type: Type.STRING, description: "Qué datos fueron filtrados" },
              actor: { type: Type.STRING, description: "Grupo de amenaza o actor detectado" },

              // Campos Exploit / ZeroDay / CVE
              nombre: { type: Type.STRING, description: "Nombre del exploit o vulnerabilidad" },
              plataforma: { type: Type.STRING, description: "Software o hardware afectado" },
              cve: { type: Type.STRING, description: "Código CVE asociado (si aplica)" },
              cveId: { type: Type.STRING, description: "Identificador CVE (formato CVE-YYYY-NNNNN)" },
              cvss: { type: Type.NUMBER, description: "Puntuación de severidad 0-10" },
              idZD: { type: Type.STRING, description: "ID interno de Zero Day si existe" },
              aplicativo: { type: Type.STRING, description: "Aplicación o vendor afectado" },
              estado: { type: Type.STRING, description: "Estado actual (Publicado, Mitigado, etc)" },

              // Campos Alerta / Fuente / Mitigacion
              titulo: { type: Type.STRING, description: "Título de la alerta o mitigación" },
              criticidad: { type: Type.STRING, description: "Nivel de criticidad (Baja, Media, Alta, Critica)" },
              categoria: { type: Type.STRING, description: "Categoría de la mitigación" },
              prioridad: { type: Type.STRING, description: "Prioridad de implementación" }
            }
          }
        },
        required: ["type", "data"]
      }
    }
  });

  return JSON.parse(response.text || '{}');
};

export const fetchTickets = async (): Promise<RiskTicket[]> => {
  return fetchResource<RiskTicket>('riesgos');
