protectedApiRouter.post('/scrape', async (req, res) => {
    const { url } = req.body;
    if (!url) return res.status(400).json({ message: "URL is required" });
    try {
        const response = await axios.get(url, {
            headers: { 'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/91.0.4472.124 Safari/537.36' },
            timeout: 8000
        });
        const $ = cheerio.load(response.data);
        $('script, style, nav, footer, iframe, header').remove();
        let content = '';
        $('article, main, .content, .post-content, p').each((_, el) => {
            const text = $(el).text().trim();
            if (text.length > 50) content += text + '\n';
        });
        res.json({ content: content.substring(0, 10000) });
    } catch (error) {
        console.error("Scrape Error:", error.message);
        res.status(500).json({ message: "No se pudo scrapear la fuente", error: error.message });
    }
});

