        <div className={viewMode === 'grid' ? "grid grid-cols-1 md:grid-cols-3 gap-6" : "space-y-4 px-6"}>
          {loading ? [1,2,3].map(i => <div key={i} className="h-48 bg-slate-100 rounded-[2rem] animate-pulse"></div>) : 
